import{l as a,a as i,c as l,Q as s}from"./chunks/framework.DMaP2wjQ.js";const m=JSON.parse('{"title":"AI 技能 (Skills)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills/index.md","filePath":"guide/skills/index.md"}'),t={name:"guide/skills/index.md"};function r(d,e,o,n,h,p){return i(),l("div",null,[...e[0]||(e[0]=[s('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/skills.md for this page in Markdown format</div><h1 id="ai-技能-skills" tabindex="-1">AI 技能 (Skills) <a class="header-anchor" href="#ai-技能-skills" aria-label="Permalink to &quot;AI 技能 (Skills)&quot;">​</a></h1><p>这里收录项目内所有 <code>fm-*</code> 技能文档。</p><h2 id="说明" tabindex="-1">说明 <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明&quot;">​</a></h2><ul><li>大多数技能都会先确认目标应用，也就是 <code>apps/&lt;app&gt;/</code></li><li>技能会优先遵循 Fantastic-mobile 的目录约定和内建能力</li><li>技能文档适合在 Codex、Claude Code 等支持 Agent Skills 的工具中直接复用</li></ul><h2 id="技能列表" tabindex="-1">技能列表 <a class="header-anchor" href="#技能列表" aria-label="Permalink to &quot;技能列表&quot;">​</a></h2><ul><li><a href="./fm-framework-settings.html">fm-framework-settings</a> - 修改框架设置</li><li><a href="./fm-i18n-manager.html">fm-i18n-manager</a> - 管理国际化</li><li><a href="./fm-page-optimizer.html">fm-page-optimizer</a> - 优化页面并替换为框架组件</li><li><a href="./fm-store-generator.html">fm-store-generator</a> - 生成 Store 模块</li><li><a href="./fm-theme-customizer.html">fm-theme-customizer</a> - 定制主题配色</li></ul><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><p>Skill 并不只限于 Codex 和 Claude Code 使用，因为 <code>SKILL.md</code> 是一个开放标准，<strong>只要 Agent 工具支持 Agent Skills 标准，通常就可以复用这些 Skill</strong> 。</p><p>本框架在 <code>skills/</code> 目录下 <strong>统一维护 Skill</strong> ，如果需要使用，可以通过 <a href="https://npmx.dev/package/skills" target="_blank" rel="noreferrer">skills</a> 包进行安装，在根目录运行下面命令：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;*&#39;</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">注意</p><p>根目录下有个 <a href="https://agents.md/" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a> 文件，能帮助 AI 更好的理解整个工程，并且大部分 Agent 都遵循这个文件。</p><p>但如果你使用的是 Claude Code，你可能需要将 <code>AGENTS.md</code> 更名为 <code>CLAUDE.md</code> ，或者给 <code>AGENTS.md</code> 做一个软链接映射到 <code>CLAUDE.md</code> 文件。</p></div>',12)])])}const k=a(t,[["render",r]]);export{m as __pageData,k as default};
